const { checkWin, checkDraw, getNextPlayer, WINNING_COMBINATIONS } = require('./game.js');

// 테스트 유틸리티
let testsPassed = 0;
let testsFailed = 0;

function assert(condition, message) {
    if (condition) {
        console.log(`✓ ${message}`);
        testsPassed++;
    } else {
        console.log(`✗ ${message}`);
        testsFailed++;
    }
}

function assertEqual(actual, expected, message) {
    if (actual === expected) {
        console.log(`✓ ${message}`);
        testsPassed++;
    } else {
        console.log(`✗ ${message} (expected: ${expected}, got: ${actual})`);
        testsFailed++;
    }
}

// 테스트 그룹
console.log('\n=== 틱택토 게임 테스트 ===\n');

// 1. 승리 감지 - 행 (Row) 테스트
console.log('📋 행 승리 감지:');
const boardRow1 = ['X', 'X', 'X', null, null, null, null, null, null];
assert(checkWin(boardRow1), 'X가 첫 번째 행에서 승리해야 함');

const boardRow2 = [null, null, null, 'O', 'O', 'O', null, null, null];
assert(checkWin(boardRow2), 'O가 두 번째 행에서 승리해야 함');

const boardRow3 = [null, null, null, null, null, null, 'X', 'X', 'X'];
assert(checkWin(boardRow3), 'X가 세 번째 행에서 승리해야 함');

// 2. 승리 감지 - 열 (Column) 테스트
console.log('\n📋 열 승리 감지:');
const boardCol1 = ['O', null, null, 'O', null, null, 'O', null, null];
assert(checkWin(boardCol1), 'O가 첫 번째 열에서 승리해야 함');

const boardCol2 = [null, 'X', null, null, 'X', null, null, 'X', null];
assert(checkWin(boardCol2), 'X가 두 번째 열에서 승리해야 함');

const boardCol3 = [null, null, 'X', null, null, 'X', null, null, 'X'];
assert(checkWin(boardCol3), 'X가 세 번째 열에서 승리해야 함');

// 3. 승리 감지 - 대각선 (Diagonal) 테스트
console.log('\n📋 대각선 승리 감지:');
const boardDiag1 = ['X', null, null, null, 'X', null, null, null, 'X'];
assert(checkWin(boardDiag1), 'X가 왼쪽 위→오른쪽 아래 대각선에서 승리해야 함');

const boardDiag2 = [null, null, 'O', null, 'O', null, 'O', null, null];
assert(checkWin(boardDiag2), 'O가 오른쪽 위→왼쪽 아래 대각선에서 승리해야 함');

// 4. 승리 감지 안 함 (No Win) 테스트
console.log('\n📋 승리 감지 안 함:');
const boardNoWin = ['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', null];
assert(!checkWin(boardNoWin), '진행 중인 게임에서 승리 감지 안 해야 함');

const boardPartial = ['X', 'X', null, 'O', 'O', null, null, null, null];
assert(!checkWin(boardPartial), '3개 연속이 아니면 승리 감지 안 해야 함');

// 5. 무승부 감지 (Draw) 테스트
console.log('\n📋 무승부 감지:');
