assertEqual(
    JSON.stringify(WINNING_COMBINATIONS[6]),
    JSON.stringify([0, 4, 8]),
    '7번째 승리 조합은 [0, 4, 8]여야 함'
);

// 8. 엣지 케이스 테스트
console.log('\n📋 엣지 케이스:');
const boardMostlyFilled = ['X', 'X', 'X', 'O', 'O', null, 'X', 'O', null];
assert(checkWin(boardMostlyFilled), 'X가 승리했으면 다른 상태와 상관없이 감지해야 함');

const boardOneMove = [null, null, null, null, null, null, null, null, 'X'];
assert(!checkWin(boardOneMove), '한 칸만 채워진 것은 승리 아님');
assert(!checkDraw(boardOneMove), '한 칸만 채워진 것은 무승부 아님');

// 테스트 결과 출력
console.log('\n' + '='.repeat(40));
console.log(`✓ 성공: ${testsPassed}개`);
console.log(`✗ 실패: ${testsFailed}개`);
console.log(`총합: ${testsPassed + testsFailed}개`);
console.log('='.repeat(40));

// 종료 코드 설정
process.exit(testsFailed > 0 ? 1 : 0);

