* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Arial', sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    text-align: center;
    background: white;
    padding: 40px;
    border-radius: 10px;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
}

h1 {
    color: #333;
    margin-bottom: 30px;
    font-size: 2.5em;
}

.game-info {
    margin-bottom: 30px;
}

.status {
    font-size: 1.2em;
    color: #555;
}

#turn {
    display: block;
    margin-bottom: 15px;
}

#turn strong {
    color: #667eea;
    font-size: 1.3em;
}

.winner-message {
    font-size: 1.3em;
    font-weight: bold;
    color: #27ae60;
    margin-top: 10px;
    min-height: 30px;
}

.board {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
    margin-bottom: 30px;
    width: 300px;
    height: 300px;
}

.cell {
    width: 100%;
    height: 100%;
    font-size: 2em;
    font-weight: bold;
    border: 2px solid #ddd;
    border-radius: 5px;
    background: #f9f9f9;
    cursor: pointer;
    transition: all 0.3s ease;
    color: #333;
}

.cell:hover:not(:disabled) {
    background: #e8e8ff;
    border-color: #667eea;
    transform: scale(1.05);
}

.cell:active:not(:disabled) {
    transform: scale(0.95);
}

.cell.x {
    color: #3498db;
}

.cell.o {
    color: #e74c3c;
}

.cell:disabled {
    cursor: not-allowed;
}

.cell.winner {
    background: #fff9e6;
    border-color: #f1c40f;
    box-shadow: 0 0 10px rgba(241, 196, 15, 0.5);
}

.reset-btn {
    padding: 12px 40px;
    font-size: 1.1em;
    font-weight: bold;
    color: white;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    border: none;
    border-radius: 5px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.reset-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 5px 20px rgba(102, 126, 234, 0.4);
}

.reset-btn:active {
    transform: translateY(0);
}

