// 승리 조건 정의
const WINNING_COMBINATIONS = [
    [0, 1, 2], // 첫 번째 행
    [3, 4, 5], // 두 번째 행
    [6, 7, 8], // 세 번째 행
    [0, 3, 6], // 첫 번째 열
    [1, 4, 7], // 두 번째 열
    [2, 5, 8], // 세 번째 열
    [0, 4, 8], // 왼쪽 위에서 오른쪽 아래 대각선
    [2, 4, 6], // 오른쪽 위에서 왼쪽 아래 대각선
];

// 승리 여부 확인 (순수 함수)
function checkWin(board) {
    return WINNING_COMBINATIONS.some((combination) => {
        const [a, b, c] = combination;
        if (
            board[a] !== null &&
            board[a] === board[b] &&
            board[a] === board[c]
        ) {
            return true;
        }
        return false;
    });
}

// 무승부 여부 확인 (순수 함수)
function checkDraw(board) {
    return board.every((cell) => cell !== null);
}

// 다음 플레이어 반환 (순수 함수)
function getNextPlayer(currentPlayer) {
    return currentPlayer === 'X' ? 'O' : 'X';
}

class TicTacToe {
    constructor() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCombinations = WINNING_COMBINATIONS;

        this.initializeEventListeners();
        this.updateUI();
    }

    initializeEventListeners() {
        // 모든 셀에 클릭 이벤트 추가
        document.querySelectorAll('.cell').forEach((cell) => {
            cell.addEventListener('click', (e) => this.handleCellClick(e));
        });

        // 리셋 버튼 이벤트
        document.getElementById('resetBtn').addEventListener('click', () => this.reset());
    }

    handleCellClick(event) {
        const cell = event.target;
        const index = parseInt(cell.dataset.index);

        // 이미 점유된 셀이거나 게임이 끝나면 무시
        if (this.board[index] !== null || this.gameOver) {
            return;
        }

        // 현재 플레이어 마크 배치
        this.board[index] = this.currentPlayer;
        cell.textContent = this.currentPlayer;
        cell.classList.add(this.currentPlayer.toLowerCase());

        // 승리 여부 확인
        if (checkWin(this.board)) {
            this.gameOver = true;
            this.winner = this.currentPlayer;
        }
        // 무승부 여부 확인
        else if (checkDraw(this.board)) {
            this.gameOver = true;
        }
        // 게임 계속
        else {
            this.switchPlayer();
        }

        this.updateUI();
    }

    highlightWinningCells(combination) {
        combination.forEach((index) => {
            const cell = document.querySelector(`[data-index="${index}"]`);
            cell.classList.add('winner');
        });
    }

    switchPlayer() {
        this.currentPlayer = getNextPlayer(this.currentPlayer);
    }

    updateUI() {
        const turnElement = document.getElementById('turn');
        const winnerElement = document.getElementById('winner');
        const cells = document.querySelectorAll('.cell');

        // 셀 비활성화 상태 업데이트
        cells.forEach((cell) => {
            if (this.gameOver) {
                cell.disabled = true;
            }
        });

        if (this.gameOver) {
            if (this.winner) {
                turnElement.textContent = `게임 종료`;
                winnerElement.textContent = `🎉 ${this.winner} 플레이어 승리!`;
            } else {
                turnElement.textContent = `게임 종료`;
                winnerElement.textContent = `무승부입니다!`;
            }
        } else {
            turnElement.innerHTML = `현재 차례: <strong>${this.currentPlayer}</strong>`;
            winnerElement.textContent = '';
        }
    }

    reset() {
        // 게임 상태 초기화
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;

        // UI 초기화
        document.querySelectorAll('.cell').forEach((cell) => {
            cell.textContent = '';
            cell.classList.remove('x', 'o', 'winner');
            cell.disabled = false;
        });

        document.getElementById('winner').textContent = '';
        this.updateUI();
    }
}

// 페이지 로드 시 게임 시작 (브라우저 환경)
if (typeof document !== 'undefined') {
    document.addEventListener('DOMContentLoaded', () => {
        new TicTacToe();
    });
}

// Node.js 테스트 환경을 위한 export
if (typeof module !== 'undefined' && module.exports) {
    module.exports = {
        checkWin,
        checkDraw,
        getNextPlayer,
        WINNING_COMBINATIONS,
        TicTacToe,
    };
}

