const { checkWin, checkDraw, getNextPlayer, WINNING_COMBINATIONS } = require('./game.js');

// 테스트 유틸리티
let testsPassed = 0;
let testsFailed = 0;

function assert(condition, message) {
    if (condition) {
        console.log(`✓ ${message}`);
        testsPassed++;
    } else {
        console.log(`✗ ${message}`);
        testsFailed++;
    }
}

function assertEqual(actual, expected, message) {
    if (actual === expected) {
        console.log(`✓ ${message}`);
        testsPassed++;
    } else {
        console.log(`✗ ${message} (expected: ${expected}, got: ${actual})`);
        testsFailed++;
    }
}

// 테스트 그룹
console.log('\n=== 틱택토 게임 테스트 ===\n');

// 1. 승리 감지 - 행 (Row) 테스트
console.log('📋 행 승리 감지:');
const boardRow1 = ['X', 'X', 'X', null, null, null, null, null, null];
assert(checkWin(boardRow1), 'X가 첫 번째 행에서 승리해야 함');

const boardRow2 = [null, null, null, 'O', 'O', 'O', null, null, null];
assert(checkWin(boardRow2), 'O가 두 번째 행에서 승리해야 함');

const boardRow3 = [null, null, null, null, null, null, 'X', 'X', 'X'];
assert(checkWin(boardRow3), 'X가 세 번째 행에서 승리해야 함');

// 2. 승리 감지 - 열 (Column) 테스트
console.log('\n📋 열 승리 감지:');
const boardCol1 = ['O', null, null, 'O', null, null, 'O', null, null];
assert(checkWin(boardCol1), 'O가 첫 번째 열에서 승리해야 함');

const boardCol2 = [null, 'X', null, null, 'X', null, null, 'X', null];
assert(checkWin(boardCol2), 'X가 두 번째 열에서 승리해야 함');

const boardCol3 = [null, null, 'X', null, null, 'X', null, null, 'X'];
assert(checkWin(boardCol3), 'X가 세 번째 열에서 승리해야 함');

// 3. 승리 감지 - 대각선 (Diagonal) 테스트
console.log('\n📋 대각선 승리 감지:');
const boardDiag1 = ['X', null, null, null, 'X', null, null, null, 'X'];
assert(checkWin(boardDiag1), 'X가 왼쪽 위→오른쪽 아래 대각선에서 승리해야 함');

const boardDiag2 = [null, null, 'O', null, 'O', null, 'O', null, null];
assert(checkWin(boardDiag2), 'O가 오른쪽 위→왼쪽 아래 대각선에서 승리해야 함');

// 4. 승리 감지 안 함 (No Win) 테스트
console.log('\n📋 승리 감지 안 함:');
const boardNoWin = ['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', null];
assert(!checkWin(boardNoWin), '진행 중인 게임에서 승리 감지 안 해야 함');

const boardPartial = ['X', 'X', null, 'O', 'O', null, null, null, null];
assert(!checkWin(boardPartial), '3개 연속이 아니면 승리 감지 안 해야 함');

// 5. 무승부 감지 (Draw) 테스트
console.log('\n📋 무승부 감지:');
const boardDraw = ['X', 'O', 'X', 'X', 'O', 'O', 'O', 'X', 'X'];
assert(checkDraw(boardDraw), '모든 셀이 차면 무승부여야 함');

const boardNotFull = ['X', 'O', 'X', 'X', 'O', 'O', 'O', 'X', null];
assert(!checkDraw(boardNotFull), '빈 셀이 있으면 무승부 아님');

const boardEmpty = [null, null, null, null, null, null, null, null, null];
assert(!checkDraw(boardEmpty), '빈 보드는 무승부가 아님');

// 6. 턴 전환 (Turn Switching) 테스트
console.log('\n📋 턴 전환:');
assertEqual(getNextPlayer('X'), 'O', 'X 다음은 O여야 함');
assertEqual(getNextPlayer('O'), 'X', 'O 다음은 X여야 함');

// 턴 전환 반복
let currentPlayer = 'X';
for (let i = 0; i < 5; i++) {
    currentPlayer = getNextPlayer(currentPlayer);
}
assertEqual(currentPlayer, 'O', '홀수 번 전환 후 O여야 함');

currentPlayer = 'X';
for (let i = 0; i < 6; i++) {
    currentPlayer = getNextPlayer(currentPlayer);
}
assertEqual(currentPlayer, 'X', '짝수 번 전환 후 X여야 함');

// 7. 승리 조합 검증
console.log('\n📋 승리 조합 정의:');
assertEqual(WINNING_COMBINATIONS.length, 8, '8가지 승리 조합이 있어야 함');
assertEqual(
    JSON.stringify(WINNING_COMBINATIONS[0]),
    JSON.stringify([0, 1, 2]),
    '첫 번째 승리 조합은 [0, 1, 2]여야 함'
);
assertEqual(
    JSON.stringify(WINNING_COMBINATIONS[6]),
    JSON.stringify([0, 4, 8]),
    '7번째 승리 조합은 [0, 4, 8]여야 함'
);

// 8. 엣지 케이스 테스트
console.log('\n📋 엣지 케이스:');
const boardMostlyFilled = ['X', 'X', 'X', 'O', 'O', null, 'X', 'O', null];
assert(checkWin(boardMostlyFilled), 'X가 승리했으면 다른 상태와 상관없이 감지해야 함');

const boardOneMove = [null, null, null, null, null, null, null, null, 'X'];
assert(!checkWin(boardOneMove), '한 칸만 채워진 것은 승리 아님');
assert(!checkDraw(boardOneMove), '한 칸만 채워진 것은 무승부 아님');

// 테스트 결과 출력
console.log('\n' + '='.repeat(40));
console.log(`✓ 성공: ${testsPassed}개`);
console.log(`✗ 실패: ${testsFailed}개`);
console.log(`총합: ${testsPassed + testsFailed}개`);
console.log('='.repeat(40));

// 종료 코드 설정
process.exit(testsFailed > 0 ? 1 : 0);
